import functools
class Solution:
    def maxMoves(self, grid):
        m, n = len(grid), len(grid[0])
        @functools.lru_cache(maxsize=None)
        def dfs(r, c):
            best = 0
            if c + 1 < n:
                for nr in (r - 1, r, r + 1):
                    if 0 <= nr < m and grid[nr][c + 1] > grid[r][c]:
                        cand = 1 + dfs(nr, c + 1)
                        if cand > best:
                            best = cand
            return best
        ans = max(dfs(r, 0) for r in range(m))
        dfs.cache_clear()
        return ans

