class Solution:
    def maxMoves(self, grid):
        m = len(grid)
        n = len(grid[0])
        dp = [True] * m
        moves = 0
        for c in range(1, n):
            new_dp = [False] * m
            any_reach = False
            for rp in range(m):
                for r in (rp - 1, rp, rp + 1):
                    if 0 <= r < m and dp[r] and grid[rp][c] > grid[r][c - 1]:
                        new_dp[rp] = True
                        any_reach = True
                        break
            if not any_reach:
                break
            dp = new_dp
            moves = c
        return moves

