var maxMoves = function(grid) {
    const m = grid.length;
    const n = grid[0].length;
    let dp = new Array(m).fill(true);
    let moves = 0;
    for (let c = 1; c < n; c++) {
        const newDp = new Array(m).fill(false);
        let anyReach = false;
        for (let rp = 0; rp < m; rp++) {
            for (const r of [rp - 1, rp, rp + 1]) {
                if (r >= 0 && r < m && dp[r] && grid[rp][c] > grid[r][c - 1]) {
                    newDp[rp] = true;
                    anyReach = true;
                    break;
                }
            }
        }
        if (!anyReach) break;
        dp = newDp;
        moves = c;
    }
    return moves;
};
